\begin{question*}{17}{a}
Write the number four hundred and eighteen thousand and seventy two in figures.
\newline

Triangles $A, B$ and $C$ are shown on the grid.
\newline

\begin{center}
\begin{tikzpicture}[x=0.6cm, y=0.6cm]
    \draw[step=1cm, gray!30, very thin] (-6.5,-6.5) grid (8.5,8.5);
    \draw[thick, ->] (-6.5,0) -- (8.5,0) node[right] {$x$};
    \draw[thick, ->] (0,-6.5) -- (0,8.5) node[above] {$y$};

    \foreach \x in {-6,-5,-4,-3,-2,-1,1,2,3,4,5,6,7,8}
        \node[below, scale=0.8] at (\x, 0) {\x};
    \foreach \y in {-6,-5,-4,-3,-2,-1,1,2,3,4,5,6,7,8}
        \node[left, scale=0.8] at (0, \y) {\y};
    \node[below left, scale=0.8] at (0,0) {0};

    % Triangle A
    \draw[thick, fill=gray!40] (-5, 4) -- (-3, 4) -- (-5, 7) -- cycle;
    \node at (-4.2, 4.8) {$A$};

    % Triangle B
    \draw[thick, fill=gray!40] (4, 3) -- (4, 5) -- (7, 5) -- cycle;
    \node at (4.8, 4.3) {$B$};

    % Triangle C
    \draw[thick, fill=gray!40] (-2, 3) -- (-1, 3) -- (-2, 4.5) -- cycle;
    \node at (-1.7, 3.5) {$C$};
\end{tikzpicture}
\end{center}

